import React from "react";
import { Link } from "react-router-dom";
import "./ModernSermonCard.css";

export interface ModernSermonCardProps {
  id: string;
  title: string;
  series?: string;
  speaker: string;
  date: string;
  passage?: string;
  description?: string;
  videoUrl?: string;
  audioUrl?: string;
  variant?: "list" | "compact";
  onClick?: () => void;
}

/**
 * ModernSermonCard - A clean, minimal sermon card without images
 * Focuses on typography and visual hierarchy
 */
const ModernSermonCard: React.FC<ModernSermonCardProps> = ({
  id,
  title,
  series,
  speaker,
  date,
  passage,
  description,
  videoUrl,
  audioUrl,
  variant = "list",
  onClick,
}) => {
  const formatDate = (dateString: string): string => {
    const date = new Date(dateString);
    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  };

  const truncateText = (text: string, maxLength: number): string => {
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength).trim() + "...";
  };

  return (
    <div
      className={`modern-sermon-card modern-sermon-card--${variant}`}
      onClick={onClick}
    >
      <div className="modern-sermon-card__content">
        {/* Series badge */}
        {series && (
          <div className="modern-sermon-card__series">{series}</div>
        )}

        {/* Title */}
        <h3 className="modern-sermon-card__title">{title}</h3>

        {/* Metadata line */}
        <div className="modern-sermon-card__metadata">
          <span className="modern-sermon-card__speaker">{speaker}</span>
          <span className="modern-sermon-card__separator">•</span>
          <span className="modern-sermon-card__date">{formatDate(date)}</span>
          {passage && (
            <>
              <span className="modern-sermon-card__separator">•</span>
              <span className="modern-sermon-card__passage">{passage}</span>
            </>
          )}
        </div>

        {/* Description */}
        {description && variant === "list" && (
          <p className="modern-sermon-card__description">
            {truncateText(description, 150)}
          </p>
        )}

        {/* Actions */}
        <div className="modern-sermon-card__actions">
          {videoUrl && (
            <a
              href={videoUrl}
              className="modern-sermon-card__action modern-sermon-card__action--primary"
              target="_blank"
              rel="noopener noreferrer"
              onClick={(e) => e.stopPropagation()}
            >
              Watch
            </a>
          )}
          {audioUrl && (
            <a
              href={audioUrl}
              className="modern-sermon-card__action modern-sermon-card__action--secondary"
              target="_blank"
              rel="noopener noreferrer"
              onClick={(e) => e.stopPropagation()}
            >
              Listen
            </a>
          )}
          {!videoUrl && !audioUrl && (
            <span className="modern-sermon-card__action modern-sermon-card__action--disabled">
              No media available
            </span>
          )}
        </div>
      </div>
    </div>
  );
};

export default ModernSermonCard;

