import React, { useState, useMemo, useEffect, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import ModernSermonCard from "../components/ModernSermonCard";
import SermonFilter from "../components/SermonFilter";
import Pagination from "../components/Pagination";
import LoadingSpinner from "../components/LoadingSpinner";
import PageContainer from "../components/PageContainer";
import { sermonsAPI, Sermon } from "../services/api";
import "./SermonSeriesDetail.css";

const SermonSeriesDetail: React.FC = () => {
  const { seriesId } = useParams<{ seriesId: string }>();
  const navigate = useNavigate();
  const [selectedSpeaker, setSelectedSpeaker] = useState("All Speakers");
  const [currentPage, setCurrentPage] = useState(1);
  const [sermons, setSermons] = useState<Sermon[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const itemsPerPage = 10; // Show 10 sermons per page

  const loadSermons = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);

      // Fetch all sermons and filter by series
      const allSermons = await sermonsAPI.getAll({
        status: "PUBLISHED",
        isPublic: "true",
      });

      // Filter by series - match seriesId to series name
      const seriesSermons = allSermons.filter((sermon) => {
        if (!sermon.series) {
          return seriesId === "standalone-sermons";
        }
        // Convert series name to ID format and compare
        const sermonSeriesId = sermon.series
          .toLowerCase()
          .replace(/\s+/g, "-")
          .replace(/[^a-z0-9-]/g, "");
        return sermonSeriesId === seriesId?.toLowerCase();
      });

      if (seriesSermons.length === 0) {
        setError("Series not found");
        return;
      }

      // Sort by date (newest first)
      seriesSermons.sort(
        (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
      );

      setSermons(seriesSermons);
    } catch (err: any) {
      console.error("Error loading sermon series:", err);
      setError(err.message || "Failed to load sermon series");
    } finally {
      setLoading(false);
    }
  }, [seriesId]);

  useEffect(() => {
    if (seriesId) {
      loadSermons();
    }
  }, [seriesId, loadSermons]);

  // Get unique speakers
  const speakers = useMemo(() => {
    const uniqueSpeakers = Array.from(new Set(sermons.map((s) => s.speaker)));
    return ["All Speakers", ...uniqueSpeakers];
  }, [sermons]);

  const filteredSermons = useMemo(() => {
    if (selectedSpeaker === "All Speakers") {
      return sermons;
    }
    return sermons.filter((sermon) => sermon.speaker === selectedSpeaker);
  }, [sermons, selectedSpeaker]);

  // Calculate pagination
  const totalPages = Math.ceil(filteredSermons.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const paginatedSermons = filteredSermons.slice(startIndex, endIndex);

  const handleSpeakerChange = (speaker: string) => {
    setSelectedSpeaker(speaker);
    setCurrentPage(1); // Reset to first page when filter changes
  };

  const handleReset = () => {
    setSelectedSpeaker("All Speakers");
    setCurrentPage(1); // Reset to first page when filter resets
  };

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
    window.scrollTo({
      top: 0,
      behavior: "smooth",
    });
  };

  if (loading) {
    return (
      <PageContainer>
        <div className="sermon-series-detail">
          <div style={{ padding: "4rem", textAlign: "center" }}>
            <LoadingSpinner message="Loading sermons..." />
          </div>
        </div>
      </PageContainer>
    );
  }

  if (error || sermons.length === 0) {
    return (
      <PageContainer>
        <div className="sermon-series-detail">
          <div className="sermon-series-detail__error">
            <h1>Series Not Found</h1>
            <p>The sermon series you're looking for doesn't exist.</p>
            <button
              onClick={() => navigate("/sermon")}
              className="sermon-series-detail__back-button"
            >
              Back to Sermon Series
            </button>
          </div>
        </div>
      </PageContainer>
    );
  }

  const seriesTitle = sermons[0]?.series || "Standalone Sermons";

  return (
    <PageContainer>
      <div className="sermon-series-detail">
        {/* Series Header */}
        <div className="sermon-series-detail__header">
          <button
            onClick={() => navigate("/sermon")}
            className="sermon-series-detail__back"
          >
            ← Back to Series
          </button>
          <div className="sermon-series-detail__badge">SERMON SERIES</div>
          <h1 className="sermon-series-detail__title">{seriesTitle}</h1>
          <p className="sermon-series-detail__count">
            {sermons.length} {sermons.length === 1 ? "Sermon" : "Sermons"}
          </p>
        </div>

        {/* Filter Section */}
        {speakers.length > 2 && (
          <div className="sermon-series-detail__filter">
            <SermonFilter
              speakers={speakers}
              selectedSpeaker={selectedSpeaker}
              onSpeakerChange={handleSpeakerChange}
              onReset={handleReset}
            />
          </div>
        )}

        {/* Sermons List */}
        <div className="sermon-series-detail__list">
          {paginatedSermons.map((sermon) => (
            <ModernSermonCard
              key={sermon.id}
              id={sermon.id}
              title={sermon.title}
              series={sermon.series}
              speaker={sermon.speaker}
              date={sermon.date}
              passage={sermon.passage}
              description={sermon.description}
              videoUrl={sermon.videoUrl}
              audioUrl={sermon.audioUrl}
              variant="list"
            />
          ))}
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="sermon-series-detail__pagination">
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              onPageChange={handlePageChange}
              showFirstLast={true}
              maxVisiblePages={5}
            />
          </div>
        )}
      </div>
    </PageContainer>
  );
};

export default SermonSeriesDetail;
